# coding: utf-8
import json
import logging
import math
import os

import click
from tabulate import tabulate

from rainbow_admin.cli import err, info
from rainbow_admin.cli.group import get_group_by_id_or_name
from rainbow_admin.file import RainbowFile

CONFIG_HEADER = [
    "id",
    "filename",
    "size",
    "editable",
    "md5",
    "operator",
    "mtime",
    "url",
    "file_version",
    "description",
]


def format_value(value):
    if not isinstance(value, str):
        value = str(value)
    more = False
    value = value.replace("\n", " ")
    if len(value) > 30:
        value = value[:27]
        more = True
    more = "..." if more else ""
    return f"{value}{more}"


SIZES = ["", "K", "M", "G", "T", "P", "E", "Z", "Y"]


def format_size(value, unit="B"):
    idx = int(math.log10(value) / 3) if value > 0 else 0
    value = round(value / math.pow(1000, idx), 2)
    try:
        level = SIZES[idx]
    except IndexError:
        level = ""
    return f"{value}{level}{unit}"


def format_config(file: RainbowFile):
    return [
        file.id,
        file.key,
        format_size(file.size),
        file.is_editable,
        file.md5,
        file.operator,
        file.mtime,
        file.url,
        file.file_version,
        file.description,
    ]


@click.group(name="file")
@click.option(
    "-g",
    "--group",
    help="id or name of group",
    show_envvar=True,
    envvar="RAINBOW_GROUP",
)
@click.pass_context
def file_cli(ctx, group):
    """actions about file group"""
    group_instance = get_group_by_id_or_name(ctx.obj["admin"], group)
    if group_instance is None:
        return
    if not group_instance.is_file:
        err(f"'{group}' 不是文件型分组")
    ctx.obj["group"] = group_instance


@file_cli.command(help="list all files")
@click.option(
    "-f",
    "--format",
    default="table",
    help="result format",
    type=click.Choice(["table", "json", "raw"]),
)
@click.pass_context
def ls(ctx, format):
    group = ctx.obj["group"]
    files = group.files

    data = [format_config(i) for i in files.values()]
    if format == "table":
        info(
            f"app_id={group.admin.app_id}, group_id={group.group_id}, group_name={group.group_name} configs:"
        )
        click.echo(tabulate(data, CONFIG_HEADER, tablefmt="pretty"))
    elif format == "json":
        click.echo(
            json.dumps(
                [i.to_dict() for i in files.values()], ensure_ascii=False, indent=4
            )
        )
    elif format == "raw":
        click.echo(json.dumps(group.get_info(), ensure_ascii=False, indent=4))


@file_cli.command(help="show file content")
@click.argument("key", required=True)
@click.pass_context
def show(ctx, key):
    group = ctx.obj["group"]
    file: RainbowFile = group.get_file(key)
    if file is None:
        err(f"未找到名为 {key} 的文件")
    if file.is_editable:
        err("此文件非文本文件")
    click.echo(file.text())


@file_cli.command(help="delete file")
@click.argument("key", required=True)
@click.pass_context
def delete(ctx, key):
    group = ctx.obj["group"]
    kv: RainbowFile = group.get_file(key)
    if kv is None:
        err(f"未找到名为 {key} 的文件")
        return
    kv.delete()
    info("删除成功")


@file_cli.command(help="upload file")
@click.argument("key", required=True)
@click.argument("filepath", required=True)
@click.option("-d", "--description", default="", help="description of group")
@click.option("-z", "--uncompress", is_flag=True, help="auto uncompress")
@click.pass_context
def upload(ctx, key, filepath, description, uncompress):
    group = ctx.obj["group"]
    if not os.path.isfile(filepath):
        err(f"{filepath} is not file")
    with open(filepath, "rb") as f:
        group.upload_file(key, f, description=description, need_uncompress=uncompress)
    info("上传成功")


@file_cli.command(help="download file")
@click.argument("key", required=True)
@click.option("-o", "--output", default=".", help="file to save")
@click.option("--intranet", is_flag=True, help="download use by cl5")
@click.pass_context
def download(ctx, key, output, intranet):
    logging.basicConfig(
        level=logging.INFO, format="[%(asctime)s: %(levelname)s] %(message)s"
    )
    group = ctx.obj["group"]
    group.is_intranet = intranet
    file: RainbowFile = group.get_file(key)
    if file is None:
        err(f"未找到名为 {key} 的文件")
        return
    file.download_to(output)
    info("下载成功")


@file_cli.command(help="download group all file to local")
@click.option("-d", "--dir", default=".", help="save to dir")
@click.option("--intranet", is_flag=True, help="download use by cl5")
@click.pass_context
def download_all(ctx, dir, intranet):
    logging.basicConfig(
        level=logging.INFO, format="[%(asctime)s: %(levelname)s] %(message)s"
    )
    group = ctx.obj["group"]
    group.is_intranet = intranet
    if os.path.isfile(dir):
        err(f"{dir} is not directory")
    if not os.path.isdir(dir):
        os.mkdir(dir)
    group.download_all_files(dir)
    info("下载成功")
